var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"AGENT_ADMIN_NPC_NULL","text":{"KOREA":"사망한 피해자들 전부 뜯어 먹힌 듯한 상처가 있습니다.","JPN":"死亡した被害者全員、食いちぎられたような傷が残っています。","ENG":"All the deceased victims show wounds consistent with having been torn apart and eaten.","TWN":"所有死者身上都有像被啃食過的傷痕。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"AGENT_ADMIN_NPC_NULL","text":{"KOREA":"이외에도 용의자 인상착의나 범죄방식이 샤레이드에서 발생한 사건과 비슷하군요.","JPN":"他にも、容疑者の容姿や犯行方法がシャレードの事件と類似しています。","ENG":"In addition, the suspect's appearance and method closely resemble the incident that occurred in Charade.","TWN":"另外，嫌犯的外貌與犯案手法，和查雷德發生的事件相當類似。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"피해자들과 마지막에 접촉한 용의자는 어떻게 됐지?","JPN":"被害者と最後に接触した後の容疑者の足取りは？","ENG":"What about the suspect who last made contact with the victims?","TWN":"最後接觸過死者的嫌犯呢？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"AGENT_ADMIN_NPC_NULL","text":{"KOREA":"피해자들과 접선장소로 이동하는 것까진 확인이 됐습니다만… 그 뒤론 연기처럼 사라졌습니다.","JPN":"被害者との待ち合わせ場所に向かう姿は確認されていますが……その後蒸発しています。","ENG":"We confirmed that they moved to the meeting location with the victims... but after that, they vanished like smoke.","TWN":"只確認到他們一同前往會合地點……之後就消失得無影無蹤了。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AGENT_ADMIN_NPC_NULL","text":{"KOREA":"순간이동 계열의 카운터일 가능성도 염두에 둬야겠군요.","JPN":"瞬間移動系のカウンターである可能性も念頭に置いたほうがいいでしょうか。","ENG":"We should also consider the possibility of a teleportation-type Counter.","TWN":"也必須考慮是空間移動類型的制裁者。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"아니. 이 일대에서 CRF반응은 포착되지 않았어.","JPN":"いや、この一帯からCRF反応は捕捉されていない。","ENG":"No. There were no CRF responses detected in the area.","TWN":"不，這一帶沒有捕捉到任何CRF反應，"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"사각지대를 골라서 빠져나간 거야.","JPN":"死角を通って抜け出したんだ。","ENG":"He deliberately slipped away through blind spots.","TWN":"他是刻意選擇死角離開的。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AGENT_ADMIN_NPC_NULL","text":{"KOREA":"한 번도 동선을 숨기지 않던 자가… 어떻게 갑자기 사각지대를 알아낸 걸까요?","JPN":"一度も移動経路を隠したことがない者が……急に死角を把握できたのはどういうわけでしょうか？","ENG":"How did someone who never bothered hiding his movements before... suddenly learn the blind spots?","TWN":"從來沒有隱藏過行蹤的人……怎麼會突然知道死角的位置？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"용의자가 사망자들과 만난 이유와 관련이 있겠지.","JPN":"容疑者が被害者と接触した理由と関係があるだろう。","ENG":"It's likely related to why the suspect met with the victims in the first place.","TWN":"應該和嫌犯接觸死者的理由有關。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"사망자들이 근래 어디에 있었는지 알아봐. 나는 내 방식대로 용의자를 찾아보겠다.","JPN":"被害者の最近までの動きを追ってくれ。私は私のやり方で容疑者を探してみる。","ENG":"Find out where the victims had been recently. I'll track down the suspect in my own way.","TWN":"調查一下死者最近的行蹤，我會用我的方式找出嫌犯。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AGENT_ADMIN_NPC_NULL","text":{"KOREA":"괜찮으시겠습니까? 샤레이드 건으로 바쁘실 텐데, 이런 작은 일은 저희에게 맡기셔도…","JPN":"よろしいのですか？　シャレードの件でお忙しいのに、こんな些細なことは私たちにお任せいただいても……","ENG":"Are you sure? You must already be busy with the Charade case. You could leave something this minor to–","TWN":"真的沒問題嗎？您應該還要忙著處理查雷德的案子，這種小事交給我們就好……"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"시니어의 역할은 도시의 모든 상황을 통찰하고 그에 맞는 판단을 내리는 거다.","JPN":"シニアの役割は都市のすべての状況を把握し、それに合った判断を下すことだ。","ENG":"A Senior's role is to grasp every situation within the city and make the appropriate judgment.","TWN":"Senior的職責是洞察城市裡的一切狀況，並做出相應判斷。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"현장직도 아니고 사람 부리는 일로 힘들다고 할 정도면 차라리 인공지능을 앉혀 놓는 게 낫지.","JPN":"現場職でもない、人に指示するだけの仕事で弱音を吐くくらいなら人工知能にシニアの座を譲ったほうがマシだろう。","ENG":"If overseeing people exhausts me this much, it'd be better to put an AI in my seat instead.","TWN":"如果連指揮人都嫌累，那乾脆換成人工智慧算了。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AGENT_ADMIN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_ADMIN_NPC_NULL","text":{"KOREA":"알겠습니다. 지시하신 건에 대해선 맡겨주시길.","JPN":"わかりました。おっしゃった件についてはお任せください。","ENG":"Understood. We'll handle the matters you assigned.","TWN":"我明白了，我會照您的指示行事。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"이 현장 사진 속 시신들… 확실히 태유대사가 쫓던 놈들의 식사 방식과 닮아있어.","JPN":"この現場写真の遺体……テユ大師が追っていたやつらの捕食の仕方とそっくりだ。","ENG":"These bodies in the photo... They match the feeding patterns of the ones Master Taeyu was tracking.","TWN":"這些現場照片裡的屍體……確實很像泰宇大師追查的那些傢伙的進食方式。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그 말괄량이를 그라운드 원에 데려올 이유론 충분하겠군.","JPN":"あのお転婆娘をグラウンド・ワンに連れて来る理由としては十分だな。","ENG":"That's reason enough to bring that troublemaker to Ground One.","TWN":"把那個野丫頭帶來G1的理由也夠充分了。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"어서 옵셔, 마사지샵 꿈꾸는 양입니다!","JPN":"いらっしゃいませ、マッサージサロン「夢見る羊」です！","ENG":"Welcome! To Dreaming Sheep Massage!","TWN":"歡迎光臨～這裡是夢寐以求的的按摩店！"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"저기 그-","JPN":"あのおー……","ENG":"Um, excuse me–","TWN":"那個—"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"넵, 어떻게 도와드릴까요?","JPN":"はいっ、どうなさいましたか？","ENG":"Yes! How may I help you?","TWN":"是，今天要做哪個項目呢？"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"이 쿠폰… 쓰려고 하는데요.","JPN":"このクーポンを……使いたいんですけど……","ENG":"I'd like to use this coupon...","TWN":"我想……使用這張優惠券。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"응? 이 쿠폰은?","JPN":"うん？　クーポン……？","ENG":"Hmm? Coupon?","TWN":"嗯？這張是？"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"어머, 잘 됐다. 기한이 오늘까지였는데 딱 맞춰오셨네요.","JPN":"あら、よかった！　期限が今日まででしたね！","ENG":"Oh, perfect timing. It expires today, and you made it just in time.","TWN":"哎呀，太好了。期限正好到今天，您來得正是時候。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그럼, 요청하신대로 [몸과 마음이 솜사탕처럼 풀어지고 녹아내리기 전까지 절대 놓아주지 않는 풀코스]로 모시겠습니다!","JPN":"では、ご希望の<color=#ffd34c>身も心もわたあめのように溶け落ちるまで絶対放さないフルコース</color>でご案内します！","ENG":"Then I'll treat you to the <color=#ffd34c>full course that won't let go until your body and mind melt away like cotton candy</color>, just as requested!","TWN":"那麼，我們將為您安排<color=#ffd34c>身心像棉花糖一樣徹底融化前，絕對不會放手的全套方案</color>！"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"이렇게 누우면 되는 건가요?","JPN":"こうやって横になればいいんですか？","ENG":"So... Do I lie down like this?","TWN":"像這樣躺下就可以了嗎？"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"네, 편하게 계세요. 시작하기 전에 아로마 향으로 릴렉스 타임 갖겠습니다.","JPN":"はい、楽にしてくださいね。まず開始前にアロマでリラックスタイムです。","ENG":"Yes, just relax. Before we begin, let's take some time to unwind with an aromatic scent.","TWN":"是的，請放輕鬆。開始前會先用精油讓您放鬆。"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"긴장이 어느 정도 풀리셨으면 처음은 어깨부터…","JPN":"緊張が少し解けましたら、最初は肩から……","ENG":"Once the tension eases a bit, we'll start with your shoulders–","TWN":"等不那麼緊繃後，會先從肩膀開始……"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"깡…?","JPN":"カチン……？","ENG":"\\"Clang\\"...?","TWN":"喀……？"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};